load("exp1_lab2.mat")

% IV and VI Characteristics
figure() %[output:00360038]
semilogx(I_q, V_in, '.', DisplayName='Voltage-Current Characteristic') %[output:00360038]
hold on; %[output:00360038]
semilogx(I_in, V_q, '.', DisplayName='Current-Voltage Characteristic') %[output:00360038]

currentQlog = log(I_q(5:101)) %[output:0ed0758f]
currentINlog = log(I_in(1:101)) %[output:1d55196b]

coeffs = polyfit(V_in(5:101), currentQlog,  1) %[output:751f723f]
% coeffs2 = polyfit(V_q2, currentINlog, 1)
% V_fit = linspace(min(V_in), max(V_q2), 1000); %[output:2582c7c1] %[output:31665111]
I_qfit = exp(coeffs(1).*V_fit + coeffs(2));
% I_infit = exp(coeffs2(1).*V_fit + coeffs2(2));
plot(I_infit, V_fit, "DisplayName","I source V measure fit")
plot(I_qfit, V_fit, "DisplayName","V source I measure fit")
% 
% vals_range = find(V_dm_25dV_60dV > -0.1 & V_dm_25dV_60dV < 0.1);
% plot_range = linspace(-0.15, 0.15, 101);
% tmp = (I_out1_25dV_60dV - I_out2_25dV_60dV);
% fit_vals = polyfit(V_dm_25dV_60dV(vals_range), tmp(vals_range), 1);
% plot(plot_range, fit_vals(1) .* plot_range + fit_vals(2), DisplayName=['Incremental Differential-Mode Transconductance Gain: y = ', num2str(fit_vals(1), 3), 'x ', char(8487), ' + ', num2str(fit_vals(2), 3), ' V'])

title('IV and VI Characteristics')
xlabel('Current (A)')
ylabel('Voltage (V)')

